async function supabaseLoadState(){
  // Supabase project uses report_settings as the shared app-state store.
  // This avoids invalid REST paths such as /rest/v1/piki_app_state when that table does not exist.
  const table=encodeURIComponent(SUPABASE_STATE_TABLE||"report_settings");
  if((SUPABASE_STATE_TABLE||"report_settings")==="report_settings"){
    const rows=await supabaseFetch(`/rest/v1/${table}?setting_name=eq.app_state&select=setting_value&limit=1`);
    const value=Array.isArray(rows)?rows[0]?.setting_value:null;
    return value?.state||value||{}
  }
  const rows=await supabaseFetch(`/rest/v1/${table}?id=eq.global&select=state&limit=1`);
  return Array.isArray(rows)&&rows[0]?.state?rows[0].state:{}
}
async function supabaseSaveState(payload){
  const updatedAt=new Date().toISOString(),stateValue={...payload,updatedAt};
  const table=encodeURIComponent(SUPABASE_STATE_TABLE||"report_settings");
  if((SUPABASE_STATE_TABLE||"report_settings")==="report_settings"){
    const body={setting_name:"app_state",setting_value:stateValue,updated_at:updatedAt};
    const rows=await supabaseFetch(`/rest/v1/${table}?on_conflict=setting_name`,{method:"POST",headers:{"Content-Type":"application/json",Prefer:"resolution=merge-duplicates,return=representation"},body:JSON.stringify(body)});
    const value=Array.isArray(rows)?rows[0]?.setting_value:null;
    return value?.state||value||stateValue
  }
  const body={id:"global",state:stateValue,updated_at:updatedAt};
  const rows=await supabaseFetch(`/rest/v1/${table}`,{method:"POST",headers:{"Content-Type":"application/json",Prefer:"resolution=merge-duplicates,return=representation"},body:JSON.stringify(body)});
  return Array.isArray(rows)&&rows[0]?.state?rows[0].state:body.state
}
