function archiveDate(value){const [y,m,d]=(value||"").split("-").map(Number);return new Date(y||1970,(m||1)-1,d||1)}
function archiveDateKey(d){return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`}
function archiveWeekStart(value){const d=archiveDate(value),day=(d.getDay()+6)%7;d.setDate(d.getDate()-day);return d}
function archiveWeekNumber(value){const d=archiveWeekStart(value),first=new Date(d.getFullYear(),0,4),firstMonday=new Date(first);firstMonday.setDate(first.getDate()-((first.getDay()+6)%7));return Math.floor((d-firstMonday)/604800000)+1}
