async function login(username,password){await syncSharedStateFromServer();const email=String(username||"").trim().toLowerCase();if(!validApprovedEmail(email))return false;const user=state.users.find(u=>String(u.email||u.username).toLowerCase()===email);if(!user)return false;user.role=normalizeRole(user.email||user.username,user.role);if(!user.passwordHash){const hasAdminPassword=state.users.some(u=>u.role==="Admin"&&u.passwordHash);if(hasAdminPassword||!isDefaultAdminEmail(email))return false;const confirmPassword=$("loginPasswordConfirm").value;if(password.length<8||password!==confirmPassword)return false;user.passwordHash=await passwordHash(password);user.role=normalizeRole(email,"Admin");user.updatedAt=new Date().toISOString();persist();await saveSharedStateToServer()}else if(user.passwordHash!==await passwordHash(password))return false;currentUser={username:user.email||user.username,role:normalizeRole(user.email||user.username,user.role)};sessionStorage.setItem(SESSION_KEY,JSON.stringify(currentUser));applyPermissions();renderAll();return true}
