function htmlSafe(value){return String(value??"").replace(/[&<>"']/g,char=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[char]))}
let aiApiBase="";
function aiBackendHint(){return"AI endpoint is not configured for this Netlify deployment."}
function aiApiBases(){return aiApiBase?[aiApiBase,""]:[""]}
function aiStaticServerError(response,data){const type=(response.headers.get("content-type")||"").toLowerCase(),message=String(data?.error||data?.message||"").toLowerCase();return[404,405,501].includes(response.status)||type.includes("text/html")||message.includes("http 404")||message.includes("http 405")}
async function aiFetch(path,options={}){let lastError=null;for(const base of aiApiBases()){let response;try{response=await fetch(`${base}/api/openai/${path}`,options)}catch(error){lastError=error;continue}const data=await response.json().catch(()=>({ok:false,error:`HTTP ${response.status}`}));if(aiStaticServerError(response,data)){lastError=new Error(`${aiBackendHint()} The current server did not provide /api/openai/${path}.`);continue}aiApiBase=base;return{response,data}}throw lastError||new Error(aiBackendHint())}
async function aiPost(path,payload={}){const {response,data}=await aiFetch(path,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});if(!response.ok||!data.ok)throw new Error(data.error||data.message||`HTTP ${response.status}`);return data}
