function setupAiSummaryBoxes(){document.querySelectorAll("#linkus-import details.cdr-section").forEach((section,index)=>{if(section.classList.contains("executive-section")){section.querySelector(":scope > .ai-summary-box")?.remove();return}if(section.querySelector(":scope > .ai-summary-box"))return;const title=section.querySelector("summary h2")?.textContent||`Analysis Section ${index+1}`,key=`analytics-${index+1}-${title.toLowerCase().replace(/[^a-z0-9]+/g,"-")}`,box=document.createElement("div");box.className="ai-summary-box";box.dataset.aiKey=key;box.dataset.aiTitle=title;box.innerHTML=`<div class="ai-summary-head"><div><p class="eyebrow">Smart Summary & Advice</p><h3>${htmlSafe(title)}</h3></div><span class="ai-summary-status">${state.aiSummaries[key]?"Saved summary":"Not generated"}</span></div><textarea class="ai-summary-text" rows="5" readonly placeholder="Generate a measurable summary explaining what happened, why it matters, and what action to take next.">${htmlSafe(state.aiSummaries[key]||"")}</textarea><div class="button-row admin-only"><button class="primary-btn generate-ai-summary" type="button">Generate Summary</button><button class="secondary-btn regenerate-ai-summary" type="button">Regenerate Summary</button><button class="secondary-btn edit-ai-summary" type="button">Edit Summary</button></div>`;section.append(box)});if(currentUser)applyPermissions()}
async function generateAiSectionSummary(box){if(currentUser?.role!=="Admin")return toast("Only Admin can generate AI summaries");if(!aiSessionId)return toast("Add an AI API key in Admin settings for this session");const status=box.querySelector(".ai-summary-status"),textarea=box.querySelector(".ai-summary-text");status.textContent="Generating…";box.querySelectorAll("button").forEach(x=>x.disabled=true);try{const result=await aiPost("summary",{session_id:aiSessionId,section:box.dataset.aiTitle,context:aiSummaryContext(box.dataset.aiTitle)});textarea.value=result.summary;textarea.readOnly=true;state.aiSummaries[box.dataset.aiKey]=result.summary;persist();status.textContent=`Generated with ${result.model||"AI"}`;toast("AI summary generated")}catch(error){status.textContent="Generation failed";toast(`AI summary failed: ${error.message}`)}finally{box.querySelectorAll("button").forEach(x=>x.disabled=false)}}
