  const timetableRange=x=>{const dates=(x.assignments||[]).map(row=>row.date).filter(Boolean);return dates.length?rangeText(dates):(x.recurringAssignments||[]).length?"Recurring weekly":"Not available"};
  const cdr=state.csvArchives.map(x=>item({id:x.id,kind:"cdr",folder:"source",category:"CDR Files",name:x.originalName||x.name,uploadedBy:x.uploadedBy||"Admin",date:x.uploadedAt,period:x.startDate&&x.endDate?`${x.startDate} to ${x.endDate}`:"Not available",records:x.records||x.summary?.total||0,status:x.status||"Imported",linked:"CSV Analytics",payload:x}));
  const timetables=state.timetableArchives.map(x=>item({id:x.id,kind:"timetable",folder:"source",category:"Timetables",name:x.name,uploadedBy:x.uploadedBy||"Admin",date:x.uploadedAt,period:timetableRange(x),records:(x.assignments||[]).length+(x.recurringAssignments||[]).length,status:x.status||"Imported",linked:"Shift Performance",payload:x}));
