function downloadCsvSectionReport(format){const card=document.querySelector("#csvInsightCards .analytics-card[open]");if(!card)return toast("Open one analysis section first");const title=card.querySelector("h3")?.textContent||"CSV Analytics Report",html=`<!doctype html><html><head><meta charset="utf-8"><title>${htmlSafe(title)}</title><style>body{font-family:Arial,sans-serif;color:#1e293b;padding:28px}h1{font-size:24px}table{width:100%;border-collapse:collapse;margin-top:16px}td,th{border:1px solid #d7dee8;padding:8px;text-align:left}.section-kpis{display:flex;gap:10px;flex-wrap:wrap}.section-kpis article{border:1px solid #d7dee8;padding:12px;min-width:140px}img{max-width:100%;height:auto}.chart-canvas{height:auto!important}</style></head><body><h1>${htmlSafe(title)}</h1><p>Generated ${new Date().toLocaleString()}</p>${htmlWithCanvasImages(card.querySelector(".analytics-card-body"))}</body></html>`;if(format==="word"){const url=URL.createObjectURL(new Blob([html],{type:"application/msword"})),a=document.createElement("a");a.href=url;a.download=`${title.replace(/\W+/g,"_")}_${iso(new Date())}.doc`;a.click();setTimeout(()=>URL.revokeObjectURL(url),1000);return}const win=window.open("","_blank");if(!win)return toast("PDF window was blocked by the browser");win.document.write(html);win.document.close();win.focus();setTimeout(()=>win.print(),350)}
