  return compact==="6400"||compact.includes("cs6400")||compact.includes("customerservice6400")||/\b(?:cs|customer|service|queue)\b.*\b6400\b/.test(text)||/\b6400\b.*\b(?:cs|customer|service|queue)\b/.test(text);
