function ensureQueueArchives(){state.queueArchives=state.queueArchives||[];return state.queueArchives}
function queuePerformanceRows(){return ensureQueueArchives().flatMap(archive=>rowsOf(archive).map(row=>({...row,_archiveName:archive.name,_archiveUploadedAt:archive.uploadedAt})))}
function compactQueueName(value){return String(value||"").toLowerCase().replace(/<\s*/g,"").replace(/\s*>/g,"").replace(/[^a-z0-9]+/g,"").trim()}
function isOfficialQueuePerformanceRow(row={}){const key=compactQueueName(row.queue||row.queue_name||row.name);return key==="cs"||key==="cs6400"}
function queuePercent(value){if(value===null||value===undefined||!Number.isFinite(+value))return null;const n=+value;return n>0&&n<=1?n*100:n}
function weightedPercent(rows,key,totalKey="total_calls"){let num=0,den=0;rows.forEach(row=>{const value=queuePercent(row[key]),weight=Number(row[totalKey]);if(Number.isFinite(value)&&Number.isFinite(weight)&&weight>0){num+=value*weight;den+=weight}});return den?num/den:null}
function weightedAverage(rows,key,totalKey="total_calls"){let num=0,den=0;rows.forEach(row=>{const value=Number(row[key]),weight=Number(row[totalKey]);if(Number.isFinite(value)&&Number.isFinite(weight)&&weight>0){num+=value*weight;den+=weight}});return den?num/den:null}
