function queuePerformanceKpis(start="",end=""){
  const rows=queueRowsForRange(start,end);
  if(!rows.length)return{available:false,source:"queue-performance",selected:OFFICIAL_CS_QUEUE_NAME,rows:[],totalCalls:0,answeredCalls:0,abandonedCalls:0,missedCalls:0,sla:null,answerRate:null,abandonRate:null,avgWait:null,avgTalk:null};
  const totalCalls=rows.reduce((sum,row)=>sum+(Number(row.total_calls)||0),0);
  let answeredCalls=rows.reduce((sum,row)=>sum+(Number(row.answered_calls)||0),0);
  let abandonedCalls=rows.reduce((sum,row)=>sum+(Number(row.abandoned_calls)||0),0);
  let missedCalls=rows.reduce((sum,row)=>sum+(Number(row.missed_calls)||0),0);
  if(!answeredCalls&&totalCalls){const rate=weightedPercent(rows,"answer_rate");if(rate!==null)answeredCalls=Math.round(totalCalls*rate/100)}
  if(!abandonedCalls&&totalCalls){const rate=weightedPercent(rows,"abandon_rate");if(rate!==null)abandonedCalls=Math.round(totalCalls*rate/100)}
  if(!missedCalls&&totalCalls)missedCalls=Math.max(0,totalCalls-answeredCalls-abandonedCalls);
  const answerRate=weightedPercent(rows,"answer_rate")??pct(answeredCalls,totalCalls);
  const abandonRate=weightedPercent(rows,"abandon_rate")??pct(abandonedCalls,totalCalls);
  const sla=weightedPercent(rows,"sla")??answerRate;
  return{available:totalCalls>0,source:"queue-performance",selected:OFFICIAL_CS_QUEUE_NAME,rows,totalCalls,answeredCalls,abandonedCalls,missedCalls,sla,answerRate,abandonRate,avgWait:weightedAverage(rows,"avg_wait_seconds"),avgTalk:weightedAverage(rows,"avg_talk_seconds")};
}
function cdrQueueText(row={}){const raw=row.raw&&typeof row.raw==="object"?Object.entries(row.raw).flatMap(([key,value])=>/queue|call\s*to|callee|to/i.test(key)?[value]:[]):[];return[row.queue,row.ring_group,row.call_flow,row.callee_number,...raw].join(" ")}
